customCss:
@import url('https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;500;600;700&family=Share+Tech+Mono&display=swap');
:root { --font-body: 'Rajdhani', sans-serif; --font-display: 'Share Tech Mono', monospace; --radius: 2px; --ambient-glow-opacity: 0.25; }

/* ═══════════════════════════════════════
   SIDEBAR — Narrowed tech panel
   ═══════════════════════════════════════ */
aside { width: 210px !important; border-right: 1px solid rgba(255,45,111,0.3) !important; box-shadow: 1px 0 30px rgba(255,45,111,0.1), inset -1px 0 0 rgba(0,240,255,0.08); backdrop-filter: none !important; background: #040308 !important; }
aside::after { content: ''; position: absolute; top: 0; right: 0; bottom: 0; width: 1px; background: linear-gradient(180deg, #00f0ff, transparent 30%, transparent 70%, #ff2d6f); pointer-events: none; }
@media (min-width: 1024px) { main#main-content:not([class*='ml-16']) { margin-left: 210px !important; } }
.sidebar-logo-icon { border: 1px solid rgba(0,240,255,0.5) !important; box-shadow: 0 0 10px rgba(0,240,255,0.3), inset 0 0 6px rgba(0,240,255,0.1); border-radius: 2px !important; }
.sidebar-logo-text { font-family: 'Share Tech Mono', monospace !important; text-transform: uppercase; letter-spacing: 0.2em; font-size: 0.65rem !important; color: #00f0ff !important; }

/* Sidebar nav items: command-line style */
.sidebar-nav-item { font-family: 'Share Tech Mono', monospace; font-size: 0.7rem !important; letter-spacing: 0.12em; text-transform: uppercase; border-radius: 2px !important; }
.sidebar-nav-item span { font-family: 'Share Tech Mono', monospace; }

/* Section headers: dim terminal labels */
.sidebar-libraries, .sidebar-personal { border-top: 1px solid rgba(0,240,255,0.08); padding-top: 0.75rem; margin-top: 0.5rem; }
.sidebar-footer { border-top: 1px solid rgba(255,45,111,0.2) !important; }

/* ═══════════════════════════════════════
   HERO — Scanlines + reduced height
   ═══════════════════════════════════════ */
.home-hero { min-height: 62dvh !important; }
@media (min-width: 1024px) { .home-hero { min-height: 68dvh !important; } }
.home-hero::after { content: ''; position: absolute; inset: 0; background: repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,0.1) 2px, rgba(0,0,0,0.1) 4px); pointer-events: none; z-index: 5; mix-blend-mode: multiply; }

/* Hero border bottom: neon line */
.home-hero { border-bottom: 1px solid rgba(255,45,111,0.4) !important; box-shadow: 0 1px 20px rgba(255,45,111,0.15); }

/* Detail hero: neon border + scanlines */
.item-detail-hero { border-bottom: 1px solid rgba(0,240,255,0.3) !important; box-shadow: 0 1px 20px rgba(0,240,255,0.1); }
.item-detail-hero::after { content: ''; position: absolute; inset: 0; background: repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,0.06) 2px, rgba(0,0,0,0.06) 4px); pointer-events: none; z-index: 5; }

/* ═══════════════════════════════════════
   CARDS — Sharp, neon-edged, perspective tilt
   ═══════════════════════════════════════ */
.media-card-image { border: 1px solid rgba(255,45,111,0.2) !important; border-radius: 2px !important; box-shadow: 0 0 0 0 transparent; transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1) !important; }
.media-card:hover .media-card-image { border-color: #00f0ff !important; box-shadow: 0 0 14px rgba(0,240,255,0.35), 0 0 35px rgba(0,240,255,0.12), inset 0 0 10px rgba(0,240,255,0.06) !important; }
.media-card:hover { transform: translateY(-5px) perspective(800px) rotateY(-1.5deg) !important; filter: brightness(1.15) !important; }

/* Card title: monospace */
.media-card a[class*='block px-1'] { font-family: 'Rajdhani', sans-serif; }

/* ═══════════════════════════════════════
   SECTION ROWS — Terminal-style headers
   ═══════════════════════════════════════ */
.section-row h2 { font-family: 'Share Tech Mono', monospace !important; text-transform: uppercase; letter-spacing: 0.15em; font-size: 0.75rem !important; }
.section-row h2 span { font-size: 0.6rem !important; }

/* ═══════════════════════════════════════
   DETAIL PAGE — Wider layout, tech feel
   ═══════════════════════════════════════ */
.page-title { font-family: 'Share Tech Mono', monospace !important; text-transform: uppercase; letter-spacing: 0.06em; }
.page-shell h2 { font-family: 'Share Tech Mono', monospace; text-transform: uppercase; letter-spacing: 0.1em; font-size: 0.8rem; }

/* ═══════════════════════════════════════
   BADGES, BUTTONS & UI ELEMENTS
   ═══════════════════════════════════════ */
.metadata-badge { border: 1px solid rgba(0,240,255,0.3) !important; border-radius: 2px !important; text-shadow: 0 0 5px rgba(0,240,255,0.4); letter-spacing: 0.1em; font-family: 'Share Tech Mono', monospace; font-size: 0.6rem !important; }
.pill { border-radius: 2px !important; }
.pill-primary { box-shadow: 0 0 14px rgba(255,45,111,0.4); border: 1px solid rgba(255,45,111,0.5); }
.pill-primary:hover { box-shadow: 0 0 22px rgba(255,45,111,0.6), 0 0 44px rgba(255,45,111,0.2); }
.pill-glass { border: 1px solid rgba(0,240,255,0.2) !important; border-radius: 2px !important; }
.action-circle { border-radius: 2px !important; border: 1px solid rgba(0,240,255,0.15); }

/* Tab bar: neon underline */
.tab-active { border-bottom: 2px solid #00f0ff !important; box-shadow: 0 2px 10px rgba(0,240,255,0.3); border-radius: 0 !important; }

/* ═══════════════════════════════════════
   GLASS & SURFACE PANELS — Hard edges
   ═══════════════════════════════════════ */
.glass, .glass-subtle, .glass-dark { border: 1px solid rgba(255,45,111,0.12) !important; border-radius: 2px !important; }
.surface-panel { border: 1px solid rgba(0,240,255,0.1) !important; border-radius: 2px !important; }
.surface-panel-subtle { border-radius: 2px !important; }

/* ═══════════════════════════════════════
   MOBILE HEADER — Neon tech bar
   ═══════════════════════════════════════ */
.mobile-header { border-radius: 2px !important; border: 1px solid rgba(255,45,111,0.25) !important; box-shadow: 0 2px 16px rgba(255,45,111,0.12); }

/* ═══════════════════════════════════════
   PROGRESS BARS & MISC
   ═══════════════════════════════════════ */
.progress-fill { box-shadow: 0 0 8px rgba(255,45,111,0.6); border-radius: 0 !important; }

/* Carousel dots: square */
.dot { border-radius: 2px !important; }
.dot-active { border-radius: 2px !important; }

/* Inputs: tech border */
input, textarea, select { border-radius: 2px !important; border-color: rgba(0,240,255,0.15) !important; }
input:focus, textarea:focus, select:focus { box-shadow: 0 0 8px rgba(0,240,255,0.2) !important; border-color: rgba(0,240,255,0.4) !important; }
